def transition(state, action):
    s = dict(state)
    # Copy the mutable structures so we never mutate the caller's state.
    s["roles"] = {r: list(perms) for r, perms in s.get("roles", {}).items()}
    s["assignments"] = {u: list(rs) for u, rs in s.get("assignments", {}).items()}
    s["history"] = list(s.get("history", []))
    req = dict(s["request"]) if s.get("request") else None

    name = action.get("name")
    params = action.get("params") or {}
    actor = action.get("agent") or params.get("actor")
    status = s.get("status", "idle")
    roles = s["roles"]
    assignments = s["assignments"]

    def holds_permission(user, permission):
        for role in assignments.get(user, []):
            if permission in roles.get(role, []):
                return True
        return False

    if name == "request":
        # Open a fresh request only when no request is in flight.
        if status in ("idle", "revoked", "denied"):
            user = params.get("user", s.get("default_user"))
            role = params.get("role", s.get("default_role"))
            if role in roles:
                req = {"user": user, "role": role, "approver": None}
                s["status"] = "requested"
                s["history"].append("request: " + str(user) + " -> " + str(role))
            else:
                s["history"].append("reject-unknown-role: " + str(role))

    elif name == "approve":
        # Only a holder of the "approve" permission may approve; RBAC check.
        if status == "requested" and req is not None:
            approver = actor or params.get("approver", s.get("default_approver"))
            if holds_permission(approver, "approve"):
                req["approver"] = approver
                s["status"] = "approved"
                s["history"].append("approve: " + str(approver))
            else:
                s["status"] = "denied"
                s["history"].append("deny (no approve permission): " + str(approver))

    elif name == "grant":
        # Materialize an approved request by assigning the role to the user.
        if status == "approved" and req is not None:
            user, role = req["user"], req["role"]
            held = assignments.setdefault(user, [])
            if role not in held:
                held.append(role)
            s["status"] = "granted"
            s["history"].append("grant: " + str(user) + " -> " + str(role))

    elif name == "revoke":
        # Withdraw a previously granted role; closes out the request.
        if status == "granted" and req is not None:
            user, role = req["user"], req["role"]
            held = assignments.get(user, [])
            if role in held:
                held.remove(role)
            s["status"] = "revoked"
            s["history"].append("revoke: " + str(user) + " -> " + str(role))

    s["request"] = req
    return s

